import re, shutil
pub=Path('pubspec.yaml').read_text()
assets=[]
for line in pub.splitlines():
    m=re.search(r'- (shaders/ifs_and_geometric/[^\s]+\.frag)', line)
    if m: assets.append(Path(m.group(1)))
for dest in sorted(set(assets)):
    src=Path('shaders/ifs_and_geometric')/dest.name
    if src.exists():
        dest.parent.mkdir(parents=True, exist_ok=True)
        shutil.move(str(src), str(dest))
        print(f'{src} -> {dest}')
    elif dest.exists():
        print(f'exists: {dest}')
    else:
        raise SystemExit(f'missing source and dest for {dest}')
