from pathlib import Path
import re, sys
root='shaders/ifs_and_geometric/'
pub=Path('pubspec.yaml').read_text()
declared={m.group(1) for m in re.finditer(r'- (shaders/ifs_and_geometric/[^\s]+\.frag)', pub)}
# Public catalog shaderAsset references are the behavior contract for this folder.
catalog=set()
for path in [Path('lib/core/modules/builders/escape_time_catalog.dart'), Path('lib/core/modules/builders/raymarched_3d_catalog.dart')]:
    text=path.read_text()
    catalog |= {m.group(1) for m in re.finditer(r"shaderAsset: '(shaders/ifs_and_geometric/[^']+\.frag)'", text)}
missing_declared=sorted(a for a in declared if not Path(a).exists())
undeclared_catalog=sorted(catalog-declared)
missing_catalog=sorted(a for a in catalog if not Path(a).exists())
root_files=sorted(str(p) for p in Path(root).glob('*.frag'))
stale=[]
for path in list(Path('lib').rglob('*.dart'))+list(Path('test').rglob('*.dart'))+[Path('pubspec.yaml')]:
    text=path.read_text()
    stale += [(str(path), m.group(0)) for m in re.finditer(r'shaders/ifs_and_geometric/[A-Za-z0-9_]+_gpu\.frag', text)]
print(f'ifs declared={len(declared)} catalog={len(catalog)} missing_declared={len(missing_declared)} undeclared_catalog={len(undeclared_catalog)} missing_catalog={len(missing_catalog)} root_frag_files={len(root_files)} stale_direct_root_refs={len(stale)}')
for label, values in [('missing_declared', missing_declared), ('undeclared_catalog', undeclared_catalog), ('missing_catalog', missing_catalog), ('root_files', root_files)]:
    if values:
        print(label+':')
        print('\n'.join(map(str, values)))
if stale:
    print('stale:')
    for p,s in stale: print(p, s)
if missing_declared or undeclared_catalog or missing_catalog or root_files or stale:
    sys.exit(1)
